const OPENLV_ICON_128
  = "data:image/svg+xml;base64,";

import { defineUnlistedScript } from "wxt/utils/define-unlisted-script";

import {
  CONTENT_MSG,
  CONTENT_SOURCE,
  PAGE_MSG,
  PAGE_SOURCE,
} from "../utils/bridge.js";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const g = globalThis as any;

export default defineUnlistedScript(() => {
  if (g.__openlv_injected) return;

  g.__openlv_injected = true;

  const origin = globalThis.location.origin;

  let requestCounter = 0;
  const pending = new Map<
    number,
    { resolve: (v: unknown) => void; reject: (e: unknown) => void; }
  >();
  const listeners = new Map<string, Set<(...args: unknown[]) => void>>();

  globalThis.addEventListener("message", (event) => {
    if (event.source !== (globalThis as unknown as Window)) return;

    if (event.data?.source !== CONTENT_SOURCE) return;

    if (event.data.type === CONTENT_MSG.RESPONSE) {
      const { requestId, result, error } = event.data as {
        requestId: number;
        result: unknown;
        error?: { message: string; code?: number; };
      };
      const entry = pending.get(requestId);

      if (entry) {
        pending.delete(requestId);

        if (error) {
          const err = new Error(error.message);

          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          (err as any).code = error.code;
          entry.reject(err);
        }
        else {
          entry.resolve(result);
        }
      }
    }

    if (event.data.type === CONTENT_MSG.EVENT) {
      const { event: eventName, data } = event.data as {
        event: string;
        data: unknown;
      };

      listeners.get(eventName)?.forEach((fn) => {
        fn(data);
      });
    }
  });

  const REQUEST_TIMEOUT_MS = 30_000;

  const eip1193 = {
    request: (payload: { method: string; params?: unknown; }) =>
      new Promise((resolve, reject) => {
        const requestId = ++requestCounter;

        const timeout = setTimeout(() => {
          pending.delete(requestId);
          reject(new Error("Request timed out"));
        }, REQUEST_TIMEOUT_MS);

        pending.set(requestId, {
          resolve: (v: unknown) => {
            clearTimeout(timeout);
            resolve(v);
          },
          reject: (e: unknown) => {
            clearTimeout(timeout);
            reject(e);
          },
        });
        globalThis.postMessage(
          {
            source: PAGE_SOURCE,
            type: PAGE_MSG.REQUEST,
            requestId,
            payload,
            userActivated: navigator.userActivation.hasBeenActive,
          },
          origin,
        );
      }),
    on: (event: string, fn: (...args: unknown[]) => void) => {
      if (!listeners.has(event)) {
        listeners.set(event, new Set());
        globalThis.postMessage(
          {
            source: PAGE_SOURCE,
            type: PAGE_MSG.SUBSCRIBE,
            event,
          },
          origin,
        );
      }

      listeners.get(event)!.add(fn);
    },
    off: (event: string, fn: (...args: unknown[]) => void) => {
      const eventListeners = listeners.get(event);

      if (!eventListeners) {
        return;
      }

      eventListeners.delete(fn);

      if (eventListeners.size === 0) {
        listeners.delete(event);
        globalThis.postMessage(
          {
            source: PAGE_SOURCE,
            type: PAGE_MSG.UNSUBSCRIBE,
            event,
          },
          origin,
        );
      }
    },
    removeListener: (event: string, fn: (...args: unknown[]) => void) => {
      eip1193.off(event, fn);
    },
    removeAllListeners: (event?: string) => {
      if (event) {
        const eventListeners = listeners.get(event);

        if (!eventListeners) {
          return;
        }

        listeners.delete(event);
        globalThis.postMessage(
          {
            source: PAGE_SOURCE,
            type: PAGE_MSG.UNSUBSCRIBE,
            event,
          },
          origin,
        );

        return;
      }

      for (const eventName of listeners.keys()) {
        globalThis.postMessage(
          {
            source: PAGE_SOURCE,
            type: PAGE_MSG.UNSUBSCRIBE,
            event: eventName,
          },
          origin,
        );
      }

      listeners.clear();
    },
  };

  if (!g.ethereum) {
    g.ethereum = eip1193;
  }

  const providerDetail = Object.freeze({
    info: {
      uuid: crypto.randomUUID(),
      name: "Open Lavatory",
      icon: OPENLV_ICON_128,
      rdns: "company.v3x.openlv.extension",
    },
    provider: eip1193,
  });

  const announceProvider = () =>
    globalThis.dispatchEvent(
      new CustomEvent("eip6963:announceProvider", { detail: providerDetail }),
    );

  globalThis.addEventListener("eip6963:requestProvider", announceProvider);
  announceProvider();
});
